import type { SyntaxNodeRef } from '@lezer/common';

import type { FilterFieldProps } from '../../../../FilterField.types.js';
import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type { FilterFieldError } from '../../../../types/filter-field-error.js';
import type {
  FilterFieldLezerNodeType,
  FilterFieldSearchOperatorNode,
} from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';
import { convertToErrorNode } from '../node-mutations.js';

/**
 * Convert a search operator node.
 * @internal
 */
export function convertSearchOperator(
  node: SyntaxNodeRef,
  doc: string,
  parserConfig?: FilterFieldProps['parserConfig'],
  context?: FilterFieldLezerNodeType,
): ConvertedLezerNode<FilterFieldSearchOperatorNode> {
  const { from, to } = node;
  const textValue = getTextFromRange(
    node,
    doc,
  ) as FilterFieldSearchOperatorNode['textValue'];
  const errors: FilterFieldError[] = [];

  const convertedNode: FilterFieldSearchOperatorNode = {
    type: 'SearchOperator',
    range: {
      from,
      to,
    },
    textValue,
    value: 'search',
  };

  // eslint-disable-next-line @typescript-eslint/no-deprecated
  if (!parserConfig?.searchConversion) {
    convertToErrorNode(convertedNode);
    errors.push({
      range: convertedNode.range,
      message: 'unsupportedSearchOperator',
    });
  } else if (context === 'FilterGroup') {
    convertToErrorNode(convertedNode);
    errors.push({
      range: convertedNode.range,
      message: 'invalidSearchOperatorInGroup',
    });
  }

  return {
    convertedNode,
    errors,
  };
}
